public sealed class CircularQueue {
    private readonly int[] _data;
    private int _head;
    private int _tail;
    private int _count;

    public CircularQueue(int capacity) {
        _data = new int[capacity];
    }

    public void Enqueue(int value) {
        if (_count == _data.Length) throw new InvalidOperationException("fila cheia");
        _data[_tail] = value;
        _tail = (_tail + 1) % _data.Length;
        _count++;
    }

    public int Dequeue() {
        if (_count == 0) throw new InvalidOperationException("fila vazia");
        int value = _data[_head];
        _head = (_head + 1) % _data.Length;
        _count--;
        return value;
    }
}

