class CircularQueue {
  constructor(capacity) {
    this.data = Array(capacity).fill(null);
    this.head = 0;
    this.tail = 0; // proxima escrita
    this.size = 0;
  }

  enqueue(value) {
    if (this.size === this.data.length) throw new Error('fila cheia');
    this.data[this.tail] = value;
    this.tail = (this.tail + 1) % this.data.length;
    this.size++;
  }

  dequeue() {
    if (this.size === 0) throw new Error('fila vazia');
    const value = this.data[this.head];
    this.head = (this.head + 1) % this.data.length;
    this.size--;
    return value;
  }
}
